module RefModule(input [7:0] a,  
                   input [7:0] b,  
                   input [7:0] c,  
                   input [7:0] d,  
                   input [7:0] e,  
                   output reg [7:0] out1,  
                   output reg [7:0] out2,  
                   output reg [7:0] out3,  
                   output reg [7:0] out4,  
                   output reg [7:0] out5);  

    reg [7:0] unused_arr [0:4];  
    integer i, j;  

    always @(*) begin  
        unused_arr[0] = a;  
        unused_arr[1] = b;  
        unused_arr[2] = c;  
        unused_arr[3] = d;  
        unused_arr[4] = e;  

        for (i = 0; i < 4; i = i + 1) begin  
            for (j = 0; j < 4 - i; j = j + 1) begin  
                if (unused_arr[j] > unused_arr[j + 1]) begin  
                    {unused_arr[j], unused_arr[j + 1]} = {unused_arr[j + 1], unused_arr[j]};  
                end  
            end  
        end  

        out1 = unused_arr[0];  
        out2 = unused_arr[1];  
        out3 = unused_arr[2];  
        out4 = unused_arr[3];  
        out5 = unused_arr[4];  
    end  
endmodule
